import os
import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime

class WorkoutTracker:
    def __init__(self):
        self.data = pd.DataFrame()
        self.supported_apps = ['Strava', 'Polar Flow', 'MyFitnessPal']

    def import_data(self, app, file_path):
        if app == 'Strava':
            self.data = self.data.append(pd.read_csv(file_path))
        elif app == 'Polar Flow':
            self.data = self.data.append(pd.read_excel(file_path))
        elif app == 'MyFitnessPal':
            self.data = self.data.append(pd.read_csv(file_path))
        else:
            print(f'Error: {app} is not a supported app.')

    def filter_by_sport(self, sport):
        self.data = self.data[self.data['sport'] == sport]

    def get_total_mileage(self):
        return self.data['distance'].sum()

    def get_total_time(self):
        return self.data['duration'].sum()

    def get_heart_rate_zones(self):
        self.data['heart_rate_zone'] = pd.cut(self.data['heart_rate'], bins=[-1, 90, 120, 150, 180, 220], labels=['Zone 1', 'Zone 2', 'Zone 3', 'Zone 4', 'Zone 5'])
        return self.data.groupby('heart_rate_zone')['duration'].sum()

    def plot_progress(self, metric):
        if metric == 'pace':
            self.data['pace'] = self.data['duration'] / self.data['distance']
            self.data.plot(x='date', y='pace')
        elif metric == 'mileage':
            self.data.plot(x='date', y='distance')
        plt.show()

