            self.data = self.data.append(pd.read_json(file_path))

    def filter_by_sport(self, sport):
        self.data = self.data[self.data['sport'] == sport]

    def aggregate_heart_rate(self):
        self.data['time_in_zone1'] = self.data['heart_rate'].apply(lambda x: sum(x < 120))
        self.data['time_in_zone2'] = self.data['heart_rate'].apply(lambda x: sum(120 <= x < 150))
        self.data['time_in_zone3'] = self.data['heart_rate'].apply(lambda x: sum(150 <= x < 180))
        self.data['time_in_zone4'] = self.data['heart_rate'].apply(lambda x: sum(x >= 180))

    def plot_progress(self, x_axis):
        if x_axis == 'pace':
            self.data.plot(x='date', y='pace', kind='line')
        elif x_axis == 'mileage':
            self.data.plot(x='date', y='distance', kind='line')
        plt.show()

