import pandas as pd
import matplotlib.pyplot as plt

class WorkoutTracker:
    def __init__(self):
        self.data = pd.DataFrame()
        self.sports = []
        self.views = ['Overall', 'By Sport']
        self.metrics = ['Mileage', 'Time', 'Heart Rate']
        self.hr_zones = ['Zone 1', 'Zone 2', 'Zone 3', 'Zone 4', 'Zone 5']

    def import_data(self, source, file_path):
        if source == 'Strava':
            self.data = pd.read_csv(file_path)
            self.data['Source'] = 'Strava'
        elif source == 'Polar Flow':
            self.data = pd.read_excel(file_path)
            self.data['Source'] = 'Polar Flow'
        elif source == 'MyFitnessPal':
            self.data = pd.read_csv(file_path)
            self.data['Source'] = 'MyFitnessPal'
        self.sports = self.data['Sport'].unique()

    def customize_view(self, view, metric):
        if view == 'By Sport':
            return self.data.groupby('Sport')[metric].sum()
        else:
            return self.data[metric].sum()

    def display_progress(self, metric):
        if metric == 'Pace':
            self.data['Pace'] = self.data['Distance'] / self.data['Time']
            self.data.plot(x='Date', y='Pace')
        elif metric == 'Mileage':
            self.data.plot(x='Date', y='Distance')
        plt.show()

    def aggregate_hr(self):
        hr_data = self.data[self.data['Heart Rate'].notnull()]
        for zone in self.hr_zones:
            if zone == 'Zone 1':
                hr_data[zone] = hr_data['Heart Rate'].apply(lambda x: x if x < 60 else 0)
            elif zone == 'Zone 2':
                hr_data[zone] = hr_data['Heart Rate'].apply(lambda x: x if 60 <= x < 70 else 0)
            elif zone == 'Zone 3':
                hr_data[zone] = hr_data['Heart Rate'].apply(lambda x: x if 70 <= x < 80 else 0)
            elif zone == 'Zone 4':
                hr_data[zone] = hr_data['Heart Rate'].apply(lambda x: x if 80 <= x < 90 else 0)
            elif zone == 'Zone 5':
                hr_data[zone] = hr_data['Heart Rate'].apply(lambda x: x if x >= 90 else 0)
        return hr_data[self.hr_zones].sum()

