import pandas as pd
import matplotlib.pyplot as plt

class WorkoutTracker:
    def __init__(self):
        self.data = pd.DataFrame()
        self.intensity_zones = {'zone1': (0, 120), 'zone2': (121, 150), 'zone3': (151, 170), 'zone4': (171, 190), 'zone5': (191, 220)}

    def import_data(self, source, file_path):
        if source == 'Strava':
            self.data = pd.read_csv(file_path)
        elif source == 'Polar Flow':
            self.data = pd.read_excel(file_path)
        elif source == 'MyFitnessPal':
            self.data = pd.read_json(file_path)
        else:
            print('Unsupported data source')

    def customize_view(self, view_type, sort_by):
        if view_type == 'export':
            self.data.to_csv('workout_data.csv')
        elif view_type == 'mileage':
            self.data = self.data.sort_values(by=sort_by, ascending=False)
        elif view_type == 'heart_rate':
            self.data['heart_rate_zone'] = self.data['heart_rate'].apply(self.classify_heart_rate)
            self.data = self.data.groupby('heart_rate_zone').sum()

    def classify_heart_rate(self, heart_rate):
        for zone, limits in self.intensity_zones.items():
            if limits[0] <= heart_rate <= limits[1]:
                return zone

    def plot_progress(self, metric):
        if metric == 'pace':
            self.data['pace'] = self.data['distance'] / self.data['duration']
            self.data.plot(x='date', y='pace')
        elif metric == 'mileage':
            self.data.plot(x='date', y='distance')
        plt.show()

