class WorkoutTrackingApp:
    def __init__(self):
        self.workouts = []
        self.sports = set()
        self.data_sources = ['Strava', 'Polar Flow', 'MyFitnessPal']

    def import_data(self):
        for source in self.data_sources:
            workout_data = self.fetch_data(source)
            self.workouts.extend(workout_data)
            self.sports.update([workout['sport'] for workout in workout_data])

    def fetch_data(self, source):
        if source == 'Strava':
            return self.fetch_strava_data()
        elif source == 'Polar Flow':
            return self.fetch_polar_flow_data()
        elif source == 'MyFitnessPal':
            return self.fetch_myfitnesspal_data()

    def fetch_strava_data(self):
        # Implement logic to fetch data from Strava API
        return [
            {'sport': 'Running', 'distance': 10.5, 'duration': 3600, 'heart_rate': {'avg': 150, 'max': 180}},
            {'sport': 'Cycling', 'distance': 25.0, 'duration': 5400, 'heart_rate': {'avg': 135, 'max': 170}}
        ]

    def fetch_polar_flow_data(self):
        # Implement logic to fetch data from Polar Flow API
        return [
            {'sport': 'Running', 'distance': 8.2, 'duration': 2700, 'heart_rate': {'avg': 160, 'max': 190}},
            {'sport': 'Swimming', 'distance': 1.5, 'duration': 2400, 'heart_rate': {'avg': 125, 'max': 150}}
        ]

    def fetch_myfitnesspal_data(self):
        # Implement logic to fetch data from MyFitnessPal API
        return [
            {'sport': 'Weight Lifting', 'duration': 3600, 'calories': 500},
            {'sport': 'Yoga', 'duration': 4500, 'calories': 300}
        ]

    def display_dashboard(self):
        self.import_data()

        # Display workout summary by sport
        print("Workout Summary by Sport:")
        for sport in self.sports:
            sport_workouts = [workout for workout in self.workouts if workout['sport'] == sport]
            total_distance = sum(workout['distance'] for workout in sport_workouts)
            total_duration = sum(workout['duration'] for workout in sport_workouts)
            print(f"{sport}: Total Distance - {total_distance:.2f} km, Total Duration - {total_duration//3600:.2f} hours")

        # Display heart rate data
        print("\nHeart Rate Summary:")
        total_time_in_zones = self.calculate_time_in_heart_rate_zones()
        for zone, duration in total_time_in_zones.items():
            print(f"Time in Zone {zone}: {duration//60:.0f} minutes")

        # Display progress graph
        self.display_progress_graph()

    def calculate_time_in_heart_rate_zones(self):
        total_time_in_zones = {'Zone 1': 0, 'Zone 2': 0, 'Zone 3': 0, 'Zone 4': 0, 'Zone 5': 0}
        for workout in self.workouts:
            if 'heart_rate' in workout:
                avg_hr = workout['heart_rate']['avg']
                if avg_hr < 120:
                    total_time_in_zones['Zone 1'] += workout['duration']
                elif avg_hr < 150:
                    total_time_in_zones['Zone 2'] += workout['duration']
                elif avg_hr < 170:
                    total_time_in_zones['Zone 3'] += workout['duration']
                elif avg_hr < 190:
                    total_time_in_zones['Zone 4'] += workout['duration']
                else:
                    total_time_in_zones['Zone 5'] += workout['duration']
        return total_time_in_zones

    def display_progress_graph(self):
        print("\nProgress Graph:")
        progress_data = self.get_progress_data()

        plt.figure(figsize=(12, 6))
        plt.plot(progress_data['date'], progress_data['pace'], label='Pace')
        plt.plot(progress_data['date'], progress_data['distance'], label='Distance')
        plt.xlabel('Date')
        plt.ylabel('Pace (min/km) / Distance (km)')
        plt.title('Workout Progress')
        plt.legend()
        plt.show()

    def get_progress_data(self):
        progress_data = {'date': [], 'pace': [], 'distance': []}
        for workout in self.workouts:
            progress_data['date'].append(datetime.datetime.now())
            progress_data['pace'].append(workout['duration'] / workout['distance'])
            progress_data['distance'].append(workout['distance'])
        return progress_data

