        for _, row in df.iterrows():
            self.data['activity_type'].append(row['Activity Type'])
            self.data['distance'].append(row['Distance'])
            self.data['duration'].append(row['Moving Time'])
            self.data['date'].append(row['Start Date'])
            self.data['heart_rate'].append(row['Average Heart Rate'])

    def import_polar(self, filepath):
        df = pd.read_csv(filepath)
        for _, row in df.iterrows():
            self.data['activity_type'].append(row['Sport'])
            self.data['distance'].append(row['Distance'])
            self.data['duration'].append(row['Duration'])
            self.data['date'].append(row['Date'])
            self.data['heart_rate'].append(row['Avg HR'])

    def import_mfp(self, filepath):
        df = pd.read_csv(filepath)
        for _, row in df.iterrows():
            self.data['date'].append(row['Date'])
            self.data['calories'].append(row['Calories'])
            self.data['carbs'].append(row['Carbs'])
            self.data['protein'].append(row['Protein'])
            self.data['fat'].append(row['Fat'])

    def customize_views(self, view_by):
        if view_by == 'sport':
            return self.data_by_sport()
        elif view_by == 'overall':
            return self.overall_stats()

    def data_by_sport(self):
        sport_data = defaultdict(list)
        for i, activity in enumerate(self.data['activity_type']):
            sport_data[activity].append({
                'distance': self.data['distance'][i],
                'duration': self.data['duration'][i],
                'date': self.data['date'][i],
                'heart_rate': self.data['heart_rate'][i]
            })
        return sport_data

    def overall_stats(self):
        total_distance = sum(self.data['distance'])
        total_duration = sum(self.data['duration'])
        heart_rate_zones = self.calculate_heart_rate_zones()
        return {
            'total_distance': total_distance,
            'total_duration': total_duration,
            'heart_rate_zones': heart_rate_zones
        }

    def calculate_heart_rate_zones(self):
        zones = defaultdict(int)
        for hr in self.data['heart_rate']:
            if hr < 120:
                zones['zone1'] += 1
            elif hr < 140:
                zones['zone2'] += 1
            elif hr < 160:
                zones['zone3'] += 1
            else:
                zones['zone4'] += 1
        return zones

    def plot_progress(self, metric):
        dates = [datetime.strptime(d, '%Y-%m-%d') for d in self.data['date']]
        if metric == 'pace':
            paces = [d / m for d, m in zip(self.data['duration'], self.data['distance'])]
            plt.plot(dates, paces)
            plt.ylabel('Pace (s/m)')
        elif metric == 'mileage':
            plt.plot(dates, self.data['distance'])
            plt.ylabel('Distance (m)')
        plt.xlabel('Date')
        plt.title('Workout Progress')
        plt.show()

