        self.data = defaultdict(list)

    def import_data(self, source, file_path):
        if source == 'Strava':
            self.import_strava(file_path)
        elif source == 'Polar Flow':
            self.import_polar_flow(file_path)
        elif source == 'MyFitnessPal':
            self.import_myfitnesspal(file_path)

    def import_strava(self, file_path):
        strava_data = pd.read_csv(file_path)
        for index, row in strava_data.iterrows():
            self.data['sport'].append(row['Activity Type'])
            self.data['distance'].append(row['Distance (km)'])
            self.data['duration'].append(row['Moving Time'])
            self.data['date'].append(pd.to_datetime(row['Start Date']))
            self.data['pace'].append(row['Average Pace (min/km)'])
            self.data['heart_rate'].append(row['Average Heart Rate'])

    def import_polar_flow(self, file_path):
        polar_data = pd.read_csv(file_path)
        for index, row in polar_data.iterrows():
            self.data['sport'].append(row['Activity Type'])
            self.data['distance'].append(row['Distance (km)'])
            self.data['duration'].append(row['Duration'])
            self.data['date'].append(pd.to_datetime(row['Timestamp']))
            self.data['heart_rate'].append(row['Average Heart Rate'])
            self.data['heart_rate_zones'].append(row['Time in Heart Rate Zones'])

    def import_myfitnesspal(self, file_path):
        myfitnesspal_data = pd.read_csv(file_path)
        for index, row in myfitnesspal_data.iterrows():
            self.data['date'].append(pd.to_datetime(row['Date']))
            self.data['calories'].append(row['Calories'])
            self.data['carbs'].append(row['Carbs (g)'])
            self.data['protein'].append(row['Protein (g)'])
            self.data['fat'].append(row['Fat (g)'])

    def customize_view(self, filter_by='sport', view_by='mileage'):
        df = pd.DataFrame(self.data)
        df['date'] = pd.to_datetime(df['date'])

        if filter_by == 'sport':
            sport_views = {}
            for sport in df['sport'].unique():
                sport_data = df[df['sport'] == sport]
                sport_views[sport] = self.generate_view(sport_data, view_by)
            return sport_views
        else:
            return self.generate_view(df, view_by)

    def generate_view(self, df, view_by):
        if view_by == 'mileage':
            return df.groupby(pd.Grouper(key='date', freq='D'))['distance'].sum().reset_index()
        elif view_by == 'pace':
            return df.groupby(pd.Grouper(key='date', freq='D'))['pace'].mean().reset_index()
        elif view_by == 'heart_rate':
            heart_rate_stats = df.groupby(pd.Grouper(key='date', freq='D'))['heart_rate'].agg(['min', 'max', 'mean']).reset_index()
            heart_rate_zones = df.groupby(pd.Grouper(key='date', freq='D'))['heart_rate_zones'].sum().reset_index()
            return pd.concat([heart_rate_stats, heart_rate_zones], axis=1)

    def plot_progress(self, view_by='mileage'):
        views = self.customize_view(view_by=view_by)

        if isinstance(views, dict):
            fig, ax = plt.subplots(figsize=(12, 6))
            for sport, view in views.items():
                ax.plot(view['date'], view[view_by], label=sport)
            ax.legend()
        else:
            fig, ax = plt.subplots(figsize=(12, 6))
            ax.plot(views['date'], views[view_by])

        ax.set_xlabel('Date')
        if view_by == 'mileage':
            ax.set_ylabel('Total Distance (km)')
        elif view_by == 'pace':
            ax.set_ylabel('Average Pace (min/km)')
        elif view_by == 'heart_rate':
            ax.set_ylabel('Heart Rate')
        plt.show()

