        if view_type == 'Workouts':
            self.data = self.data[self.data['Activity Type'].isin(filter_criteria)]
        elif view_type == 'Mileage':
            self.data = self.data[self.data['Distance'] >= filter_criteria]
        elif view_type == 'Heart Rate':
            self.data = self.data[self.data['Heart Rate'] >= filter_criteria[0]]
            self.data = self.data[self.data['Heart Rate'] <= filter_criteria[1]]
        elif view_type == 'Time':
            self.data = self.data[self.data['Duration'] >= filter_criteria]

