            mask = (self.data['Heart Rate'] >= hr_zones[i]) & (self.data['Heart Rate'] < hr_zones[i + 1])
            hr_time.append(self.data.loc[mask, 'Duration'].sum())
        return pd.Series(hr_time, index=hr_labels)

    def plot_progress(self, metric):
        if metric == 'Pace':
            self.data['Pace'] = self.data['Duration'] / self.data['Distance']
            self.data.plot(x='Date', y='Pace')
        elif metric == 'Mileage':
            self.data.plot(x='Date', y='Distance')
